import argparse
from kafka.admin import NewTopic, AdminClient
from kafka.errors import TopicAlreadyExistsError

def get_admin_client(broker_list):
    try:
        return AdminClient(bootstrap_servers=broker_list)
    except Exception as e:
        print(f"Failed to connect to Kafka cluster: {e}")
        exit()

def create_topic(admin_client, topic_name, num_partitions):
    new_topic = NewTopic(topic_name, 3, num_partitions)
    try:
        admin_client.create_topics(new=new_topic)
        print(f"Created topic: {topic_name}")
    except TopicAlreadyExistsError as e:
        print(f"Topic {topic_name} already exists.")

def configure_topic(admin_client, topic_name, config):
    try:
        admin_client.describe_configs([topic_name])
        if config['cleanup.policy'] != 'compact':
            admin_client.alter_replica_assignment(topic_name=topic_name, new_replication_factor=config['replicas'])
        if config['retention.ms'] is not None:
            admin_client.alter_topic_config( topic_name = topic_name,
                                            config = { 'cleanup.policy': config['cleanup.policy'],
                                                       'delete.retention.ms' : config['delete.retention.ms'],
                                                       'segment.ms' : config['segment.ms']})
    except Exception as e:
        print(f"Failed to configure topic: {e}")

def main():
    parser = argparse.ArgumentParser(description='Kafka Topic Management')
    parser.add_argument('-b', '--bootstrap-servers', help='Kafka bootstrap servers (comma-separated)', required=True)
    parser.add_argument('-t', '--topic-name', help='Topic name', required=True)
    parser.add_argument('-p', '--num-partitions', help='Number of partitions for the topic', type=int, default=3)
    parser.add_argument('--config', action='append', nargs='+', help='Configure a specific setting')
    
    args = parser.parse_args()
    
    admin_client = get_admin_client(args.bootstrap_servers.split(','))

    if args.config is not None:
        config = dict(zip(['key','value'],args.config[0]))
        configure_topic(admin_client, args.topic_name, config)

    create_topic(admin_client, args.topic_name, args.num_partitions)
    

if __name__ == "__main__":
    main()